import{_ as l,o as e,c as t,a2 as i}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"余额通交易规则","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/cash-plus/cash-plus-trading-rules.md","filePath":"zh-CN/funds-and-wealth/cash-plus/cash-plus-trading-rules.md"}'),s={name:"funds-and-wealth/cash-plus/cash-plus-trading-rules.md"};function r(n,a,u,d,h,o){return e(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="余额通交易规则" tabindex="-1">余额通交易规则 <a class="header-anchor" href="#余额通交易规则" aria-label="Permalink to &quot;余额通交易规则&quot;">​</a></h1><p>场景：余额通 - 转入、转出、计息、交易时间、收益计算</p><p>用户可能问：余额通什么时候自动转入、余额通怎么计算收益、7 日年化利率是什么意思、资金到账后多久开始计息、取消余额通协议资金怎么处理</p><p>自动转入规则：</p><ul><li>开通余额通后，账户闲置资金每日固定时间自动转入货币基金</li><li>资金到账后，1 个交易日内自动转入并开始计息</li></ul><p>自动转出规则：</p><ul><li>买股票、缴纳费用等需要扣款时，系统自动赎回对应金额</li><li>取消余额通协议后，持仓全部转出</li></ul><p>各地区每天固定时间自动执行转入转出操作：香港新版 8:30、香港旧版 9:10、新加坡 10:00。</p><p>收益说明：</p><ul><li>近 7 日收益：过去 7 个自然日内实际派发的收益总和</li><li>7 日年化利率：以近 7 日收益换算为年化利率，反映当前收益水平，仅供参考，不代表未来收益</li></ul><p>当前各基金 7 日年化利率见上方实时数据。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth/余额通常见问题">余额通常见问题</a> — 余额通规则与常见问题</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth">基金与理财</a></li></ul>',15)])])}const _=l(s,[["render",r]]);export{c as __pageData,_ as default};
